 <template>
   <view class="index">
	
	<text>111</text>
     <view class="tn-page"></view>
 
     <tn-tabbar :beforeSwitch="beforeSwitch" v-model="currentIndex" :list="tabbarList"></tn-tabbar>
	
   </view>
   
 </template>
 
 <script>
	
   export default {
	  
     data() {
		 
       return {
         // 底部tabbar菜单数据
         tabbarList: [{
             title: '首页',
             activeIcon: 'home-fill',
             inactiveIcon: 'home'
           },
           {
             title: '报单',
             activeIcon: 'order-fill',
             inactiveIcon: 'order'
           },
           {
             title: '信息',
             activeIcon: 'message-fill',
             inactiveIcon: 'message'
           },
           {
             title: '我的',
             activeIcon: 'my-fill',
             inactiveIcon: 'my'
           } 
         ],
         // tabbar当前被选中的序号
         currentIndex: 0
       } 
     },
	 methods: {
		beforeSwitch(index) {
		        // 只能切换偶数项
		        if (index % 1 == 0) return true
		        else return false
		      }
		}
   }
 </script>
 
